### 4. PostgreSQL Generator
\`\`\`rust
pub struct PostgresDdlGenerator;

impl DdlGenerator for PostgresDdlGenerator {
    fn dialect(&self) -> &'static str { "postgres" }

    fn generate(&self, op: &SchemaOp) -> Vec<String> {
        match op {
            SchemaOp::AlterColumn { table, from, to } => {
                // Postgres uses separate ALTER statements for each change
                let mut stmts = Vec::new();

                if from.sql_type != to.sql_type {
                    stmts.push(format!("ALTER TABLE {} ALTER COLUMN {} TYPE {}",
                        table, to.name, to.sql_type));
                }

                if from.nullable != to.nullable {
                    let action = if to.nullable { "DROP NOT NULL" } else { "SET NOT NULL" };
                    stmts.push(format!("ALTER TABLE {} ALTER COLUMN {} {}",
                        table, to.name, action));
                }

                stmts
            }
            // ... other Postgres-specific implementations
        }
    }
}
