                indexes: vec![],
                foreign_keys: vec![
                    ForeignKeySchema {
                        name: Some("fk_heroes_team".into()),
                        columns: vec!["team_id".into()],
                        referenced_table: "teams".into(),
                        referenced_columns: vec!["id".into()],
                        on_delete: ReferentialAction::SetNull,
                        on_update: ReferentialAction::NoAction,
