pub fn detect_relationship_kind(ty: &syn::Type) -> Option<RelationshipKind> {
    let type_str = quote::quote!(#ty).to_string();

    if type_str.starts_with("Related <") || type_str.contains("Related<") {
        Some(RelationshipKind::ManyToOne) // Default for Related<T>
    } else if type_str.starts_with("RelatedMany <") || type_str.contains("RelatedMany<") {
        Some(RelationshipKind::OneToMany) // Default for RelatedMany<T>
    } else if type_str.starts_with("Lazy <") || type_str.contains("Lazy<") {
        Some(RelationshipKind::ManyToOne) // Lazy also defaults to ManyToOne
    } else {
        None
    }
}
